from flask import Flask, request, jsonify, session
import functools
import random

app = Flask(__name__)
app.secret_key = 'your_secret_key'

users_db = {
    'user1': {'password': 'pass1', 'mfa_enabled': True, 'otp': None},
    'user2': {'password': 'pass2', 'mfa_enabled': False, 'otp': None}
}

def login_required(f):
    @functools.wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user' not in session:
            return jsonify({'error': 'Login required'}), 401
        return f(*args, **kwargs)
    return decorated_function

def generate_otp(user):
    otp = random.randint(100000, 999999)
    users_db[user]['otp'] = otp
    print(f"Generated OTP for {user}: {otp}")

@app.route('/login', methods=['POST'])
def login():
    data = request.json
    username = data.get('username')
    password = data.get('password')
    
    if username not in users_db or users_db[username]['password'] != password:
        return jsonify({'error': 'Invalid credentials'}), 403

    session['user'] = username
    if users_db[username]['mfa_enabled']:
        generate_otp(username)
        return jsonify({'message': 'OTP required'})
    else:
        return jsonify({'message': 'Access granted'})

@app.route('/verify-otp', methods=['POST'])
@login_required
def verify_otp():
    data = request.json
    otp = data.get('otp')
    user = session['user']
    
    if users_db[user]['otp'] == otp:
        users_db[user]['otp'] = None
        return jsonify({'message': 'Access granted'})
    else:
        return jsonify({'error': 'Invalid OTP'}), 403

@app.route('/api/direct-login', methods=['POST'])
def api_direct_login():
    data = request.json
    username = data.get('username')
    password = data.get('password')
    
    if username not in users_db or users_db[username]['password'] != password:
        return jsonify({'error': 'Invalid credentials'}), 403

    return jsonify({'message': 'Access granted'})

if __name__ == '__main__':
    app.run(debug=True)